#include <iostream>
class MatrixRow {
    double* m_data{};
    int m_size{};
public:
    MatrixRow() = default;
    MatrixRow(int size) : m_data{ new double[size]{} }, m_size{ size } {}
    ~MatrixRow() { delete[] m_data; }
    MatrixRow(const MatrixRow& src)
        : m_data{ src.m_size > 0 ? new double[src.m_size] : nullptr }, m_size{ src.m_size } {
        for (int i{ 0 }; i < m_size; ++i) m_data[i] = src.m_data[i];
    }
    MatrixRow& operator=(const MatrixRow& src) {
        if (this != &src) {
            delete[] m_data; m_size = src.m_size;
            m_data = m_size > 0 ? new double[m_size] : nullptr;
            for (int i{ 0 }; i < m_size; ++i) m_data[i] = src.m_data[i];
        }
        return *this;
    }
    MatrixRow(MatrixRow&& src) noexcept
        : m_data{ src.m_data }, m_size{ src.m_size } {
        src.m_data = nullptr; src.m_size = 0;
    }
    MatrixRow& operator=(MatrixRow&& src) noexcept {
        if (this != &src) {
            delete[] m_data; m_data = src.m_data; m_size = src.m_size;
            src.m_data = nullptr; src.m_size = 0;
        }
        return *this;
    }
    void set(int index, double val) { m_data[index] = val; }
    int size() const { return m_size; }
    void print() const {
        for (int i{ 0 }; i < m_size; ++i) {
            if (i > 0) std::cout << ' ';
            std::cout << m_data[i];
        }
        std::cout << '\n';
    }
};
MatrixRow makeFilledRow(int n, double val) {
    MatrixRow row{ n };
    for (int i{ 0 }; i < n; ++i) row.set(i, val);
    return row;
}
int main() {
    int n{}; double val{};
    std::cin >> n >> val;
    MatrixRow a{ makeFilledRow(n, val) };
    a.print();
    MatrixRow b{ a };
    b.print();
    MatrixRow c{};
    c = makeFilledRow(n, val);
    c.print();
    std::cout << (c.size() == n ? "valid" : "invalid") << '\n';
    return 0;
}
